Here's a modern MSTest approach for `DataFetcher`, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode status = HttpStatusCode.OK,
        string content = "ok",
        TimeSpan? delay = null)
    {
        var handler = new FakeHandler(status, content, delay);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsBody()
    {
        var (fetcher, _) = CreateFetcher(content: "hello world");

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CallerCancels_ThrowsTaskCanceledException()
    {
        var (fetcher, _) = CreateFetcher(delay: TimeSpan.FromSeconds(30));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_Timeout_IsCancelledCooperatively()
    {
        // TestContext.CancellationToken fires when [Timeout] expires,
        // so a slow handler triggers cooperative cancellation automatically.
        var (fetcher, _) = CreateFetcher(delay: TimeSpan.FromSeconds(30));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [DataRow(HttpStatusCode.BadRequest)]
    [DataRow(HttpStatusCode.Forbidden)]
    [DataRow(HttpStatusCode.NotFound)]
    public async Task FetchAsync_NonSuccessStatus_Throws(HttpStatusCode status)
    {
        var (fetcher, _) = CreateFetcher(status);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    /// <summary>Minimal fake handler — no mocking library needed.</summary>
    private sealed class FakeHandler(
        HttpStatusCode status, string content, TimeSpan? delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay is { } d)
                await Task.Delay(d, cancellationToken); // respects token

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(ms)]` + `_testContext.CancellationToken` — MSTest fires the token when the timeout expires |
| **Caller cancellation** | Pre-cancelled `CancellationTokenSource` — verifies `FetchAsync` propagates it |
| **Exception assertions** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Data-driven errors** | `[DataRow]` parameterizes multiple HTTP status codes |
| **No mocking library** | A simple `FakeHandler` gives full control over `HttpClient` behavior |

The critical insight: pass `TestContext.CancellationToken` into your async calls so `[Timeout]` can cancel them cooperatively rather than forcibly aborting the thread.
